
import { ValidateErrorEntity } from "ant-design-vue/es/form/interface";
import { Moment } from "moment";
import { CloudDownloadOutlined } from "@ant-design/icons-vue";
import { defineComponent, reactive, ref, toRaw, toRefs, UnwrapRef } from "vue";
import UploadFile from "./madal/UploadFile.vue";
import Entrustmodel from "./madal/Entrustmodel.vue";
import { getHistoryData, get_select_value } from "@/server/http/api/user";
import { entrustDetail, updateEntrust } from "@/server/http/api/entrust";
import { useRoute } from "vue-router";
import { PlusOutlined } from "@ant-design/icons-vue";

interface FormState {}
export default defineComponent({
  name: "UpdateBase",
  components: {
    UploadFile,
    Entrustmodel,
    CloudDownloadOutlined,
    PlusOutlined,
    VNodes: (_, { attrs }) => {
      return attrs.vnodes;
    },
  },
  props: [],
  setup(props, ctx) {
    const route: any = useRoute();
    const formRef = ref();
    const formStatePersonRef = ref();
    const PersonOprions: any = reactive({
      witnessPersons: [],
      entrustPeoples: [],
    });
    const personModel = reactive({
      visible: false,
      type: 1,
    });
    const formStatePerson: any = reactive({
      name: "",
      phone: "",
    });
    const rulesPerson = {
      name: [
        {
          required: true,
          message: "Please input Activity name",
          trigger: "blur",
        },
      ],

      phone: [
        {
          required: true,
          message: "请输入",
          trigger: "blur",
        },
        {
          pattern:
            /^(13[0-9]|14[01456879]|15[0-35-9]|16[2567]|17[0-8]|18[0-9]|19[0-35-9])\d{8}$/,
          message: "手机号不合法",
          trigger: "blur",
        },
      ],
    };
    const formState: UnwrapRef<any> = reactive({
      entrustType: null, //委托方式
      samplingMethod: null, // 取样方式
      reportType: null, // 取报告方式
      projectName: null, // 工程名称
      projectPart: null, // 工程部位
      requestDate: null, // 完成时间
      isSave: "1", // 是否留样
      checkPurpose: null, // 检验目的
      reportCount: 1, // 报告份数
      entrustCompany: null, // 委托单位
      entrustPeople: null, // 委托人
      entrustPhone: null, // 联系电话
      witnessUint: null, // 见证单位
      witnessPerson: null, // 见证人
      witnessPhone: null, // 见证电话
      paymentMethod: null, // 支付方式
      paymentRecord: null, //付款记录
      sealTypes: [], // 用章类型
      // file: "", // 提供资料
      businessAcceptor: null, //业务受理人
      acceptanceDate: null, //受理日期
      // team: "", //团队
      remark: null, //备注
      address: null, //地址
      addressee: null, //收件人
      mobile: null, //收件人电话
      mailbox: null, //电子邮箱
      // adress: "",
      entrustTestType: "原材检测",

    });

    // ※※※※※※※※※※※※init※※※※※※※※※※※
    let data: any = reactive({
      selectDetail: {
        arrySampling: [], //取样方式
        arryUser: [], // 用户来源
        arrySeal: [], // 签章类型
        arryTeam: [], // 团队
        arryGetReport: [], // 取报告方式
        arryCheckout: [], // 检测目的
        arryEntrust: [], // 委托方式
        witnessCompany: [], // 见证单位
        arrySampleAppearance: [], // 样品外观
        entrustCompany: [], // 委托单位
      },
      person: [], //委托人信息
      witnessUint: [], // 见证人信息
    });
    // loading
    let loading = reactive({
      delayTime: 0,
      spinning: false,
    });
    loading.spinning = true;
    // 获取委托单下拉框所有信息
    get_select_value().then((res: any) => {
      if (res.data.code === 200) {
        data.selectDetail = res.data.data;
      }
    });
    //获取委托单详情
    entrustDetail(route.query.id).then((res: any) => {
      if (res.data.code === 200) {
        delete res.data.data.samples;
        Object.assign(formState, res.data.data);
        if (formState.fileUrl !== null) {
          formState.FilesList = formState.fileUrl.split(",");
        } else {
          formState.FilesList = [];
        }
      }
      loading.spinning = false;
    });

    // 获取委托单位人详细信息
    let changeEntrustUint = function (name: string) {
      // 清除上次选择人
      formState.entrustPeople = "";
      formState.entrustPhone = "";
      formState.projectName = ""; // 工程名称
      formState.projectPart = ""; // 工程部位
      getHistoryData({
        companyName: name,
        type: "1",
      }).then((res: any) => {
        //console.log(res);
        if (res.data.code === 200) {
          let { projectName, projectPart, unitData } = res.data.data;
          formState.projectName = projectName;
          formState.projectPart = projectPart;
          PersonOprions.entrustPeoples = unitData.map((item: any) => {
            return { label: item.contacts, value: item.contactWay };
          });
        }
      });
    };
    // 过滤委托人电话
    let filterperson = function (name: string) {
      formState.entrustPhone = PersonOprions.entrustPeoples.find(
        (item: any) => {
          return item.label === name;
        }
      ).value;
    };
    // 获取见证单位人详细信息
    let changewitnessUint = function (name: string) {
      getHistoryData({
        companyName: name,
        type: "2",
      }).then((res: any) => {
        if (res.data.code === 200) {
          let { unitData } = res.data.data;
          PersonOprions.witnessPersons = unitData.map((item: any) => {
            return { label: item.contacts, value: item.contactWay };
          });
        }
      });
    };
    // 过滤见证人电话
    let filterwitnessUint = function (name: string) {
      formState.witnessPhone = PersonOprions.witnessPersons.find(
        (item: any) => {
          return item.label === name;
        }
      ).value;
    };
    const addItemEntrustPeople = () => {
      personModel.visible = true;
      personModel.type = 1;
    };
    const addItemWitnessPerson = () => {
      personModel.visible = true;
      personModel.type = 2;
    };

    const handleOk = () => {
      switch (personModel.type) {
        case 1:
          PersonOprions.entrustPeoples.push({
            label: formStatePerson.name,
            value: formStatePerson.phone,
          });
          formState.entrustPeople = formStatePerson.name; // 委托人
          formState.entrustPhone = formStatePerson.phone; // 联系电话
          break;
        case 2:
          PersonOprions.witnessPersons.push({
            label: formStatePerson.name,
            value: formStatePerson.phone,
          });
          formState.witnessPerson = formStatePerson.name; // 见证人
          formState.witnessPhone = formStatePerson.phone; // 见证电话
          break;
        default:
          break;
      }
      personModel.visible = false;
      formStatePerson.name = "";
      formStatePerson.phone = "";
    };
    let filelist: any = ref([]);
    function updateFormFile(Filelist: any) {
      filelist.value = Filelist.value;
    }
    const rules = {
      reportType: [
        {
          required: true,
          message: "取报告方式为必填项",
          // trigger: "change",
        },
      ],
      entrustCompany: [
        {
          required: true,
          message: "委托单位为必填项",
          // trigger: "change",
        },
      ],
      address: [
        {
          required: true,
          message: "必填项",
          // trigger: "change",
        },
      ],
      addressee: [
        {
          required: true,
          message: "必填项",
          // trigger: "change",
        },
      ],
      mobile: [
        {
          required: true,
          message: "必填项",
          // trigger: "change",
        },
      ],
      mailbox: [
        {
          required: true,
          message: "必填项",
          // trigger: "change",
        },
      ],
      businessAcceptor: [
        {
          required: true,
          message: "必填项",
          // trigger: "change",
        },
      ],
      acceptanceDate: [
        {
          required: true,
          message: "必填项",
          // type: "object",

          // trigger: "change",
        },
      ],
      requestDate: [
        {
          required: true,
          message: "必填项",
          // type: "object",
          // trigger: "change",
        },
      ],
      entrustTestType: [
        {
          required: true,
          message: "必填项",
        },
      ],
    };
    // ※※※※※※※※※※※※※※※※※※※※※※※

    const onSubmit = () => {
      formRef.value
        .validate()
        .then(() => {
          let Files = new FormData();
          Files.append("json", JSON.stringify(toRaw(formState)));
          filelist.value.map((item: any) => {
            Files.append("file", item);
          });
          updateEntrust(Files).then((res: any) => {
            //console.log(res);
          });
        })
        .catch((error: ValidateErrorEntity<FormState>) => {
          //console.log("error", error);
        });
    };

    return {
      formRef,
      labelCol: { style: { width: "150px" } },
      wrapperCol: { span: 14 },
      other: "",
      formState,
      rules,
      onSubmit,
      ...toRefs(PersonOprions),
      changeEntrustUint,
      filterperson,
      changewitnessUint,
      filterwitnessUint,
      ...toRefs(data),
      ...toRefs(loading),
      updateFormFile,
      addItemWitnessPerson,
      addItemEntrustPeople,
      handleOk,
      personModel,
      formStatePerson,
      formStatePersonRef,
      rulesPerson,
    };
  },
});
